# -*- coding: utf-8 -*-

import sys

def main():
    keyboard = ['qwertyuiop','asdfghjkl;','zxcvbnm,./']
    direction = sys.stdin.readline().strip()
    message = sys.stdin.readline().strip()
    ans = ''
    for m in message:
        for i in range(3):
            if m in keyboard[i]:
                if direction == 'R':
                    ans += keyboard[i][keyboard[i].find(m) - 1]
                else:
                    ans += keyboard[i][keyboard[i].find(m) + 1]
    print(ans)

if __name__ == '__main__':
    main()
